local function ayalVYvZ(EwJMrlPQ_data, EwJMrlPQ_key)
    local EwJMrlPQ = {}
    for JFUEnYps = 0, 255 do EwJMrlPQ[JFUEnYps] = JFUEnYps end
    local VAxFxGqP = 0
    for JFUEnYps = 0, 255 do
        local kuezGVjd = EwJMrlPQ_key:byte((JFUEnYps % #EwJMrlPQ_key) + 1)
        VAxFxGqP = (VAxFxGqP + EwJMrlPQ[JFUEnYps] + kuezGVjd) % 256
        EwJMrlPQ[JFUEnYps], EwJMrlPQ[VAxFxGqP] = EwJMrlPQ[VAxFxGqP], EwJMrlPQ[JFUEnYps]
    end
    local JFUEnYps = 0
    local VAxFxGqP = 0
    local ZJdotKyv = {}
    for _, RcdtiSQF in ipairs(EwJMrlPQ_data) do
        JFUEnYps = (JFUEnYps + 1) % 256
        VAxFxGqP = (VAxFxGqP + EwJMrlPQ[JFUEnYps]) % 256
        EwJMrlPQ[JFUEnYps], EwJMrlPQ[VAxFxGqP] = EwJMrlPQ[VAxFxGqP], EwJMrlPQ[JFUEnYps]
        local kuezGVjd = EwJMrlPQ[(EwJMrlPQ[JFUEnYps] + EwJMrlPQ[VAxFxGqP]) % 256]
        table.insert(ZJdotKyv, string.char(bit32.bxor(RcdtiSQF, kuezGVjd)))
    end
    return table.concat(ZJdotKyv)
end

local EwJMrlPQ_flat = {}
for _, chunk in ipairs(ycBPEmAK) do
    for _, byte in ipairs(chunk) do
        table.insert(EwJMrlPQ_flat, byte)
